from torchvision import transforms

class ImageDataset(Dataset):
    def __init__(self, root_dir, transforms=None):
        self.images = list_images(root_dir)
        self.transforms = transforms

    def __len__(self):
        return len(self.images)

    def __getitem__(self, idx):
        # Load image
        image = load_image(self.images[idx])

        # Apply preprocessing (on-the-fly)
        if self.transforms:
            image = self.transforms(image)

        return image

# Define transforms for generative training
transforms = transforms.Compose([
    transforms.Resize((256, 256)),
    transforms.RandomHorizontalFlip(),
    transforms.ColorJitter(brightness=0.2, contrast=0.2),
    transforms.ToTensor()  # Convert to PyTorch tensor [web:32]
])

dataset = ImageDataset("/path/to/images", transforms=transforms)

# WRONG: loads all 100K images into RAM on dataset construction
class BadDataset(Dataset):
    def __init__(self, paths):
        self.images = [load_image(p) for p in paths]  # 10 GB peak RAM

# RIGHT: store only paths; load lazily in __getitem__
class GoodDataset(Dataset):
    def __init__(self, paths):
        self.paths = paths  # negligible memory

    def __len__(self):
        return len(self.paths)

    def __getitem__(self, idx):
        return load_image(self.paths[idx])  # loaded on demand by each worker

# WRONG: sqlite3 connections are not picklable — crashes DataLoader with num_workers > 0
class BadDataset(Dataset):
    def __init__(self, db_path):
        self.conn = sqlite3.connect(db_path)  # cannot be pickled to workers

    def __getitem__(self, idx):
        return self.conn.execute("SELECT * FROM samples WHERE id=?", (idx,)).fetchone()

# RIGHT: store only the path; open connection inside __getitem__
class GoodDataset(Dataset):
    def __init__(self, db_path):
        self.db_path = db_path  # a string is picklable

    def __getitem__(self, idx):
        conn = sqlite3.connect(self.db_path)  # each worker opens its own connection
        row = conn.execute("SELECT data FROM samples WHERE id=?", (idx,)).fetchone()
        conn.close()
        return row
